-- =============================================================================
-- Historical DCR backfill — ENTRIES part 3 of 9  (535 days)
-- Run 01_catalog.sql first. Run parts in order. Idempotent (upsert). STAGING first.
-- =============================================================================
on conflict (entry_date, movie_id, screen_id) do update set
  shows=excluded.shows, share=excluded.share, cinema_id=excluded.cinema_id,
  updated_by='dcr-historical-import', updated_at=now();

on conflict (entry_date, movie_id, screen_id) do update set
  shows=excluded.shows, share=excluded.share, cinema_id=excluded.cinema_id,
  updated_by='dcr-historical-import', updated_at=now();

commit;